import { useEffect, useState } from 'react';
import api from '../../api/client';

const emptyForm = {
  username: '',
  email: '',
  password: '',
  confirm_password: '',
  role: 'GENERAL',
  is_active: true,
};

export default function UsersAdminSection() {
  const [users, setUsers] = useState([]);
  const [form, setForm] = useState(emptyForm);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);

  const loadUsers = async () => {
    try {
      const res = await api.get('/auth/users-admin/');
      setUsers(Array.isArray(res.data) ? res.data : res.data.results || []);
    } catch (err) {
      console.error('Failed to load users', err);
      setUsers([]);
    }
  };

  useEffect(() => {
    loadUsers();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({
      ...prev,
      [name]: name === 'is_active' ? value === 'true' : value,
    }));
  };

  const handleAddClick = () => {
    setEditingId(null);
    setForm(emptyForm);
    setShowForm(true);
  };

  const handleEdit = (user) => {
    setEditingId(user.id);
    setForm({
      username: user.username || '',
      email: user.email || '',
      password: '',
      confirm_password: '',
      role: user.role || 'GENERAL',
      is_active: user.is_active ?? true,
    });
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    try {
      await api.delete(`/auth/users-admin/${id}/`);
      loadUsers();
    } catch (err) {
      console.error('Failed to delete user', err);
      alert('Failed to delete user');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!editingId && form.password !== form.confirm_password) {
      alert('Password and Confirm Password do not match');
      return;
    }

    const payload = {
      username: form.username,
      email: form.email,
      role: form.role,
      is_active: form.is_active,
    };

    if (form.password) {
      payload.password = form.password;
    }

    try {
      if (editingId) {
        await api.put(`/auth/users-admin/${editingId}/`, payload);
      } else {
        await api.post('/auth/users-admin/', payload);
      }

      setForm(emptyForm);
      setEditingId(null);
      setShowForm(false);
      loadUsers();
    } catch (err) {
      console.error('Failed to save user', err);
      alert('Failed to save user');
    }
  };

  return (
    <div className="card mb-4">
      <div className="card-body">
        <div className="d-flex justify-content-between align-items-center mb-3">
          <h4 className="mb-0">Users</h4>
          <button className="btn btn-primary" onClick={handleAddClick}>
            Add User
          </button>
        </div>

        {showForm && (
          <form className="row g-3 mb-4" onSubmit={handleSubmit}>
            <div className="col-md-4">
              <label className="form-label">Username</label>
              <input
                className="form-control"
                name="username"
                value={form.username}
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-4">
              <label className="form-label">Email</label>
              <input
                className="form-control"
                type="email"
                name="email"
                value={form.email}
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-4">
              <label className="form-label">Role</label>
              <select
                className="form-select"
                name="role"
                value={form.role}
                onChange={handleChange}
              >
                <option value="ADMIN">ADMIN</option>
                <option value="SUPPORT">SUPPORT</option>
                <option value="DEVELOPER">DEVELOPER</option>
                <option value="GENERAL">GENERAL</option>
              </select>
            </div>

            <div className="col-md-4">
              <label className="form-label">Password</label>
              <input
                className="form-control"
                type="password"
                name="password"
                value={form.password}
                onChange={handleChange}
                required={!editingId}
              />
            </div>

            <div className="col-md-4">
              <label className="form-label">Confirm Password</label>
              <input
                className="form-control"
                type="password"
                name="confirm_password"
                value={form.confirm_password}
                onChange={handleChange}
                required={!editingId}
              />
            </div>

            <div className="col-md-4">
              <label className="form-label">Is Active</label>
              <select
                className="form-select"
                name="is_active"
                value={String(form.is_active)}
                onChange={handleChange}
              >
                <option value="true">True</option>
                <option value="false">False</option>
              </select>
            </div>

            <div className="col-12">
              <button className="btn btn-success me-2" type="submit">
                {editingId ? 'Update User' : 'Save User'}
              </button>
              <button
                className="btn btn-secondary"
                type="button"
                onClick={() => {
                  setShowForm(false);
                  setEditingId(null);
                  setForm(emptyForm);
                }}
              >
                Cancel
              </button>
            </div>
          </form>
        )}

        <div className="table-responsive">
          <table className="table table-bordered">
            <thead>
              <tr>
                <th>ID</th>
                <th>Username</th>
                <th>Email</th>
                <th>Role</th>
                <th>Active</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {users.length ? (
                users.map((user) => (
                  <tr key={user.id}>
                    <td>{user.id}</td>
                    <td>{user.username}</td>
                    <td>{user.email}</td>
                    <td>{user.role || ''}</td>
                    <td>{user.is_active ? 'Yes' : 'No'}</td>
                    <td>
                      <button
                        className="btn btn-sm btn-warning me-2"
                        onClick={() => handleEdit(user)}
                      >
                        Edit
                      </button>
                      <button
                        className="btn btn-sm btn-danger"
                        onClick={() => handleDelete(user.id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="6">No users found</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
